/**
 * 清理函数：每次刷新前调用此函数进行清理
 * @param passageID 通道
 * @param passageData 通道储存的数据
 */
function imageLayerPassageClear(passageID: number, passageData: ImagePassageData) {
    // -- 判断该通道是图片的话
    if (passageData.type == passageType) {
        // 清理注册的移动
        if (passageData.timeFunc) {
            os.remove_ENTERFRAME(passageData.timeFunc, this);
        }
        var a: UIBitmap = passageData.displayObject;
        // 存在且不是来自显示图片的话
        if (a && !passageData.uiBitmapFromShow) {
            a.dispose();
        }
    }
}
/**
