//------------------------------------------------------------------------------------------------------
function createImageMoveData(sp: GameSprite, data: ImagePassageData) {
    newCmdParams = ObjectUtils.depthClone(data.lastImageCmdParams);
    newCmdParams.dpX = sp.dpX;
    newCmdParams.dpY = sp.dpY;
    newCmdParams.dpZ = sp.dpZ;
    newCmdParams.rotation = sp.rotation1;
    newCmdParams.dpWidth = sp.dpWidth;
    newCmdParams.dpHeight = sp.dpHeight;
    newCmdParams.passageID = data.passageID;
    newCmdData = data;
}
/**
 * 当来自操作工具的属性修改时
 * @param type 类别 0-移动 1-缩放 2-旋转  
 * @param realSelObjs 选中的工具
 */
function imageLayerOnToolsChange(type: number, realSelObjs: GameSprite[]) {
    // 根据选中的数据进行获取
    for (var i = 0; i < realSelObjs.length; i++) {
        var sp = realSelObjs[i];
        var data: ImagePassageData = sp.data;
        // 如果存在数据且数据类别是当前指令的类别时
        if (data && data.type == passageType && data.cmd.customID == commandID) {
            // 实际坐标转化为深度坐标
            var res = sp.realCoordToDPCoord(type == 0, type == 1);
            // 选中的指令是当前指令时：则直接修改属性
            if (previewWin.currentSelectCmd == data.cmd) {
                var passageID: number = data.passageID as any;
                if (type == 0) {
                    previewWin.modifyCommandParam(data.cmd, "dpX", sp.dpX);
                    previewWin.modifyCommandParam(data.cmd, "dpY", sp.dpY);
                }
                else if (type == 1) {
                    previewWin.modifyCommandParam(data.cmd, "dpWidth", res.dpWidth);
                    previewWin.modifyCommandParam(data.cmd, "dpHeight", res.dpHeight);
                }
                else {
                    previewWin.modifyCommandParam(data.cmd, "rotation", sp.rotation);
                }
            }
            else {
                // 不存在数据时则创建
                if (newCmdParams == null) {
                    createImageMoveData(sp, data);
                }
                // 否则直接修改
                else {
                    if (type == 0) {
                        newCmdParams.dpX = sp.dpX;
                        newCmdParams.dpY = sp.dpY;
                    }
                    else if (type == 1) {
                        newCmdParams.dpWidth = res.dpWidth;
                        newCmdParams.dpHeight = res.dpHeight;
                    }
                    else {
                        newCmdParams.rotation = sp.rotation;
                    }
                }
            }
        }
    }
}
/**
 * 刷新图片实际的显示
 * @param uiBitmap 图片对象
 * @param cmdParams 参数（可能为空）
 * @param passageData 通道数据
 * @param needSyncCMDParams [可选] 默认值=false 是否同步指令参数
 * @param needResizeWhenEmptyImage [可选] 默认值=false 是否重置尺寸当空图片时
 */
function refreshImageRealShow(uiBitmap: UIBitmap, cmdParams: ThisCommandParams, passageData: ImagePassageData, needSyncCMDParams: boolean = false, needResizeWhenEmptyImage: boolean = false) {
    var toImage: string;
    var paramData = cmdParams ? cmdParams : passageData;
    // 来自非显示图片的情况下
    if (!passageData.uiBitmapFromShow) {
        if (paramData.refImageEnabled) {
            toImage = paramData.refImage ? paramData.refImage : emptyImageURL;
        }
        else if (passageData.refImageEnabled) {
            toImage = passageData.refImage ? passageData.refImage : emptyImageURL;
        }
        else {
            toImage = emptyImageURL;
        }
        // 原图是空图片的话允许重置为新图的尺寸
        if (needResizeWhenEmptyImage && uiBitmap.image == emptyImageURL) {
            passageData.displayObject["_emptyImage"] = true;
            if (needSyncCMDParams) {
                passageData.displayObject.once(EventObject.LOADED, this, (passageData: ImagePassageData) => {
                    previewWin.modifyCommandParam(passageData.cmd, "dpWidth", passageData.displayObject.dpWidth);
                    previewWin.modifyCommandParam(passageData.cmd, "dpHeight", passageData.displayObject.dpHeight);
                }, [passageData]);
            }
        }
        uiBitmap.image = toImage;
    }
}

