var passageType = "gcImage";
var PLUGIN_CUSTOM_COMMAND_showPicture = 3001;
var PLUGIN_CUSTOM_COMMAND_movePicture = 3002;
var PLUGIN_CUSTOM_COMMAND_earsePicture = 3008;
