3003.cmdPreviewTS:
//------------------------------------------------------------------------------------------------------
// 编辑器预览窗口运行时提供的系统变量
// 关于预览的流程：
// -- 1.imageLayerPassageClear 每已使用的通道x每已使用的指令
// -- 2.runCommand 每个指令按顺序执行一遍
// -- 3.imageLayerPassageStart 每已使用的通道x每已使用的指令
// 关于播放的流程
// -- 1.imageLayerPassageClear 每已使用的通道x每已使用的指令
// -- 2.runCommand 每个指令按顺序播放
//------------------------------------------------------------------------------------------------------
/**
 * 当前自定义指令的编号
 */
declare var commandID: number;
/**
 * 图像层通道数据
 */
declare var imageLayerPassageData: any[];
/**
 * 图像层显示对象容器
 */
declare var imageLayer: GameImageLayer;
/**
 * 界面层显示对象容器
 */
declare var uiLayer: GameSprite;
/**
 * 预览窗口
 */
declare var previewWin: {
    /**
     * 清理全部事件指令产生的预览效果
     */
    clearData: Function;
    /**
     * 设置数据，刷新预览效果直到当前选中的指令行
     */
    setData: Function;
    /**
     * 当前选中的指令
     */
    currentSelectCmd: Command;
    /**
     * 视图区域是否右键移动过
     */
    viewAreaRightMouseMove: boolean;
    /**
     * 允许显示全部对象
     */
    allowAllDisplayObject: boolean;
    /**
     * 对象操作工具
     */
    operateObjectTool: {
        // 刷新对象操作工具，比如来自其他地方更改了对象的位置或尺寸等，可使用该函数刷新
        refresh: Function;
        // 选中对象
        selectObjects: (sp: GameSprite[]) => void;
        // 需要排除缩放和旋转工具的对象
        addExcludeOperactionObject: (sp: GameSprite) => void
    }
    /**
     * 图像层镜头操作工具
     * onChange(changeType:number,cameraX:number,cameraY:number,cameraZ:number,cameraRotation:number)
     */
    openCameraTools: (onChange: Function) => void;
    /**
     * 刷新图像层镜头工具，根据当前镜头值
     */
    refreshCameraTools: Function;
    /**
     * 选中事件指令
     * @param cmd 事件指令
     * @param sendEvent 派发事件 默认=false 派发事件会刷新属性栏、预览窗口等
     */
    selectCmdMessageByCmd(cmd: Command, sendEvent?: boolean);
    /**
     * 修改指令属性
     * @param cmd 需要修改的指令
     * @param varName 参数变量名称
     * @param newValue 新的值
     */
    modifyCommandParam: (cmd: Command, varName: string, newValue: any) => void;
    /**
     * 新增指令 默认是默认值，如果有写入参数的话则以参数为准 varNameValue
     * @param customID 自定义ID
     * @param varNameValue 额外的变量值，如存在则优先使用该值，否则使用自定义编辑器中的默认值，如 {dpX:100,dpY:200}
     * @param selectedIndex [可选] 默认值=-2  -3=当前选中（之后） -2=当前选中（之前） -1=最尾端 0-N=自定义 
     * @param refreshPreViewArea [可选] 默认值=true 刷新预览区
     */
    insertCustomCMD(customID: number, varNameValue: any, selectedIndex?: number, refreshPreViewArea?: boolean): Command;
    /**
     * 更改显示层
     * @param selectedIndex 0-界面层 1-图像层
     */
    changeLayer(selectedIndex: number): void;
    /**
     * 创建菜单
     * var menuData:any[] = [
               {
                   label:"重命名",
                   splitLine:false,// 是否显示分割线
                   children:[], // 存放和本身这个对象是一样的格式
                   execute:"functionName", // 点击后执行的方法名称
                   shortcutKey:"", //显示的快捷键名称
                   menuHotKey:"", //实际作用的快捷键名称 对应Laya.KeyBoard的值 如A
                   enabled:true, // 是否可用，不填写表示true
                   visible:true, // 是否显示，不填写表示true
				   selected:true, // 如果存在则以打钩的形式选择此项
				   group:"myGroupName" // 配合selected，如若存在则同组单选
               }
           ];
     * @param menuData 菜单数据
     * @param x 全局坐标X
     * @param y 全局坐标Y
     * @param executeDomain 函数作用域
     */
    createMenu(menuData: any[], x: number, y: number, executeDomain: any);
}
//------------------------------------------------------------------------------------------------------
// 通道数据
//------------------------------------------------------------------------------------------------------
declare class CameraData {
    // ====> system 必要项
    /**
     * 通道编号
     */
    passageID: number;
    /**
     * 类别，一般用于区分显示对象，如图片、动画、立绘、界面都是属于不同的类别
     */
    type: string;
    /**
     * 记录关联的指令
     */
    cmd: Command;
    /**
     * 当通道覆盖时调用的函数，以便清理掉。如显示了2号图片或移动了号图片，再次显示2号图片时会清理掉此前显示的图片或移动行为
     */
    onCoverPassage: Function;
    // ====> custom 自定义属性
    x: number;
    y: number;
    z: number;
    rotation: number;
    timeFunc: Function
}
//------------------------------------------------------------------------------------------------------
// 自定义变量
//------------------------------------------------------------------------------------------------------
var passageType = "gcImageLayerCamera";
//------------------------------------------------------------------------------------------------------
// [everyone used command] 逐指令行目执行
//------------------------------------------------------------------------------------------------------
/**
 * 逐指令执行：对应事件下按照从上至下的顺序逐行执行，如果是该自定义指令时则会执行该函数
 * 该函数用于编辑器预览和播放，如果分歧面板中筛选不经过的事件指令则不会执行该函数。
 * 比如事件页中有3个该指令，则按照顺序执行3次该函数
 * @param cmdParams 指令的自定义参数数据，根据用户设定值
 * @param cmd 对应的指令对象
 * @param isPlayMode 是否是播放模式，否则是普通的预览模式
 */
function runCommand(cmdParams: ThisCommandParams, cmd: Command, isPlayMode: boolean) {
    // 如果使用了变量则忽略掉该镜头指令
    if (cmdParams.xUseVar || cmdParams.yUseVar || cmdParams.zUseVar || cmdParams.roUseVar) {
        return;
    }
    // 获取镜头所在的通道数据（图像层这里规定了固定占用10001号通道）
    var passageID = 10001;
    var passageData: CameraData = imageLayerPassageData[passageID];
    if (!passageData) passageData = imageLayerPassageData[passageID] = {} as any;
    passageData.type = passageType;
    passageData.cmd = cmd;
    // 播放模式的情况
    if (isPlayMode) {
        // 清理时间函数
        if (passageData.timeFunc) {
            os.remove_ENTERFRAME(passageData.timeFunc, this);
        }
        var m = {
            time: cmdParams.time,
            curTime: 1,
            x: imageLayer.camera.viewPort.x,
            y: imageLayer.camera.viewPort.y,
            z: imageLayer.camera.z,
            rotation: imageLayer.camera.rotation,
            x2: cmdParams.cameraX - imageLayer.camera.viewPort.x,
            y2: cmdParams.cameraY - imageLayer.camera.viewPort.y,
            z2: cmdParams.cameraZ - imageLayer.camera.z,
            rotation2: cmdParams.cameraRotation - imageLayer.camera.rotation,
            transData: GameUtils.getTransData(cmdParams.trans)
        }
        if (cmdParams.timeType == 0) {
            imageLayer.camera.viewPort.x = cmdParams.cameraX;
            imageLayer.camera.viewPort.y = cmdParams.cameraY;
            imageLayer.camera.z = cmdParams.cameraZ;
            imageLayer.camera.rotation = cmdParams.cameraRotation;
        }
        else {
            var f: Function;
            os.add_ENTERFRAME(f = passageData.timeFunc = (cmdParams: ThisCommandParams) => {
                var per = m.curTime / m.time;
                var value = GameUtils.getValueByTransData(m.transData, per);
                imageLayer.camera.viewPort.x = m.x2 * value + m.x;
                imageLayer.camera.viewPort.y = m.y2 * value + m.y;
                imageLayer.camera.z = m.z2 * value + m.z;
                imageLayer.camera.rotation = m.rotation2 * value + m.rotation;
                m.curTime++;
                if (per == 1) {
                    os.remove_ENTERFRAME(arguments.callee, this);
                }
                imageLayer.updateFrame(true);
            }, this, [cmdParams]);
            f.apply(this, [cmdParams]);
        }
    }
    else {
        passageData.x = cmdParams.cameraX;
        passageData.y = cmdParams.cameraY;
        passageData.z = cmdParams.cameraZ;
        passageData.rotation = cmdParams.cameraRotation;
    }
}
//------------------------------------------------------------------------------------------------------
// 属性面板修改：当修改该指令的属性时，只会执行该指令对应的「指令源」的这些函数
// 如A指令来自自定义指令32号，每次通过属性面板快速修改A指令的参数b时，则会执行32号指令的下面2个函数
// [current used command] 
//------------------------------------------------------------------------------------------------------
/**
 * 当属性面板中的属性修改前
 * @param cmd 对应的指令
 * @param cmdParams 对应指令的参数 
 * @param varName 修改的属性名
 */
function onCommandAttributeBeforeChange(cmd: Command, cmdParams: ThisCommandParams, varName: string) {

}
/**
 * 当属性面板中的属性修改后
 * @param cmd 对应的指令
 * @param cmdParams 对应指令的参数 
 * @param varName 修改的属性名
 * @param newValue 修改后的值
 */
function onCommandAttributeChange(cmd: Command, cmdParams: ThisCommandParams, varName: string, value: any) {
    // 如果使用了变量则忽略掉该镜头指令
    if (varName == "xUseVar" || varName == "yUseVar" || varName == "zUseVar" || varName == "roUseVar") {
        previewWin.setData(false);
        return;
    }
    // 如果使用了变量的话就忽略掉
    if (cmdParams.xUseVar || cmdParams.yUseVar || cmdParams.zUseVar || cmdParams.roUseVar) {
        return;
    }
    // 获取通道数据
    if (varName == "cameraX") {
        imageLayer.camera.viewPort.x = value;
    }
    else if (varName == "cameraY") {
        imageLayer.camera.viewPort.y = value;
    }
    else if (varName == "cameraZ") {
        imageLayer.camera.z = value;
        this.refreshCameraTools();
    }
    else if (varName == "cameraRotation") {
        imageLayer.camera.rotation = value;
        this.refreshCameraTools();
    }
    Callback.CallLaterBeforeRender(this.operateObjectTool.refresh, this.operateObjectTool);
}
//------------------------------------------------------------------------------------------------------
// 对象操作工具
// [everyone used command type] 遍历每个执行过的自定义指令类别
//------------------------------------------------------------------------------------------------------
/**
 * 当操作工具移动对象时
 * @param realSelObjs 选中的对象
 */
function imageLayerOnToolsChangePostion(realSelObjs: GameSprite[]): void {

}
/**
 * 当操作工具缩放时
 * @param realSelObjs 选中的对象
 */
function imageLayerOnToolsChangeSize(realSelObjs: GameSprite[]) {

}
/**
 * 当操作工具旋转时
 * @param realSelObjs 选中的对象
 */
function imageLayerOnToolsChangeRotation(realSelObjs: GameSprite[]) {

}
/**
 * 当操作工具开始操作时
 */
function imageLayerOnToolsChangeStart(realSelObjs: GameSprite[]) {

}
/**
 * 当操作工具结束操作时
 */
function imageLayerOnToolsChangeEnd(realSelObjs: GameSprite[]) {

}
/**
 * 当操作工具选中对象时
 */
function imageLayerOnToolsSelectObject(realSelObjs: GameSprite[]) {

}
//------------------------------------------------------------------------------------------------------
// 图像层相关 遍历每个已使用的通道，每个已使用的通道再遍历已使用的指令，调用下面的函数
// [everyone passage] x [everyone used command type]
//------------------------------------------------------------------------------------------------------
/**
 * 清理函数：每次刷新前调用此函数进行清理
 * @param passageID 通道
 * @param passageData 通道储存的数据
 */
function imageLayerPassageClear(passageID: number, passageData: CameraData) {
    // -- 该通道是镜头的话：清理镜头移动并重置镜头
    if (passageData.type == passageType) {
        if (passageData.timeFunc) {
            os.remove_ENTERFRAME(passageData.timeFunc, this);
        }
        imageLayer.camera.viewPort.x = 0;
        imageLayer.camera.viewPort.y = 0;
        imageLayer.camera.z = 0;
        imageLayer.camera.rotation = 0;
        imageLayer.updateFrame();
    }
}
/**
 * 开始函数
 * @param passageID 通道
 * @param passageData 通道储存的数据
 */
function imageLayerPassageStart(passageID: number, passageData: CameraData) {
    // -- 该通道是镜头的话：直接设置，此处用于窗口预览而非播放
    if (passageData.type == passageType) {
        imageLayer.camera.viewPort.x = passageData.x;
        imageLayer.camera.viewPort.y = passageData.y;
        imageLayer.camera.z = passageData.z;
        imageLayer.camera.rotation = passageData.rotation;
        imageLayer.updateFrame();
        if (passageData.cmd == previewWin.currentSelectCmd) {
            // 打开图像层镜头操作工具
            previewWin.openCameraTools((changeType: number, cameraX: number, cameraY: number, cameraZ: number, cameraRotation: number) => {
                if (changeType == 0) {
                    previewWin.modifyCommandParam(passageData.cmd, "cameraRotation", cameraRotation);
                }
                else if (changeType == 1) {
                    previewWin.modifyCommandParam(passageData.cmd, "cameraX", cameraX);
                    previewWin.modifyCommandParam(passageData.cmd, "cameraY", cameraY);
                }
                else if (changeType == 2) {
                    previewWin.modifyCommandParam(passageData.cmd, "cameraZ", cameraZ);
                }
            })
        }
    }
}

