 * @param cmd 对应的指令对象
 * @param isPlayMode 是否是播放模式，否则是普通的预览模式
 */
function runCommand(cmdParams: ThisCommandParams, cmd: Command, isPlayMode: boolean) {
    // 使用变量作为通道的话则忽略此指令执行
    if (cmdParams.passageIDUseVar) {
        return;
    }
    // -- 获取通道数据
    var passageData: any = imageLayerPassageData[cmdParams.passageID];
    // -- 获取储存的通道，没有的话则新建
    if (isPlayMode) {
        if (passageData) {
            passageData.onCoverPassage && passageData.onCoverPassage.apply(this, [cmdParams.passageID, passageData]);
            // 清除数据重新开始
            passageData = null;
        }
    }
    else {
        if (passageData) {
            delete imageLayerPassageData[cmdParams.passageID];
        }
    }
}
